-- =====================================================================
-- Deepholm Downport  --  21  Quest-credit SmartAI (ported from Neltharion 4.3.4)
-- ---------------------------------------------------------------------
-- The flagged quest credits the TDB lacked, ported from the fully-scripted
-- Neltharion 4.3.4 repack (our exact entry ids). 29-col -> DC 31-col remap
-- (event_param5/6 inserted = 0). Includes the creatures' timed_actionlists.
-- Trigger/cast spells these reference are added by 22_credit_spells (extracted
-- from the Cata client). Supersedes the flagged placeholders in 18.
-- =====================================================================

UPDATE `creature_template` SET `AIName`='SmartAI' WHERE `entry` IN (42465,42466,43027,43028,43029,43038,43164,43165,43166,43167,43388,43597,43640,43649,43805,43978,44025,44051,44133,44135,44218,44228,44229,44281,44290,44768,44772,44900,44938,45083,45091,46139,53744) AND (`AIName`='' OR `AIName` IS NULL);

DELETE FROM `smart_scripts` WHERE (`source_type`=0 AND `entryorguid` IN (42465,42466,43027,43028,43029,43038,43164,43165,43166,43167,43388,43597,43640,43649,43805,43978,44025,44051,44133,44135,44218,44228,44229,44281,44290,44768,44772,44900,44938,45083,45091,46139,53744))
  OR (`source_type`=9 AND `entryorguid` IN (4246600,4246601,4421800));

